CREATE TABLE `t_merchant` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(64) NOT NULL,
  `owner_name` varchar(64) DEFAULT NULL,
  `phone` varchar(32) DEFAULT NULL,
  `business_hours` varchar(64) DEFAULT NULL,
  `password_hash` varchar(128) DEFAULT NULL,
  `category` varchar(64) NOT NULL,
  `address` varchar(255) DEFAULT NULL,
  `notice` varchar(255) DEFAULT NULL,
  `image_url` varchar(255) DEFAULT NULL,
  `longitude` decimal(10,6) NOT NULL,
  `latitude` decimal(10,6) NOT NULL,
  `distance_km` decimal(10,2) NOT NULL DEFAULT '0.00',
  `min_order_amount` decimal(10,2) NOT NULL DEFAULT '20.00',
  `delivery_fee` decimal(10,2) NOT NULL DEFAULT '4.00',
  `delivery_mode` varchar(32) NOT NULL DEFAULT 'FAST',
  `delivery_area_type` varchar(32) NOT NULL DEFAULT 'RADIUS',
  `delivery_radius_km` decimal(6,2) NOT NULL DEFAULT '5.00',
  `delivery_polygon` text,
  `estimated_delivery_minutes` int NOT NULL DEFAULT '30',
  `avg_score` decimal(3,1) NOT NULL DEFAULT '4.8',
  `monthly_sales` int NOT NULL DEFAULT '0',
  `status` varchar(32) NOT NULL DEFAULT 'ACTIVE',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=26 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
