--
-- Table structure for table `t_order`
--

DROP TABLE IF EXISTS `t_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t_order` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `order_no` varchar(64) NOT NULL,
  `user_id` bigint NOT NULL,
  `merchant_id` bigint NOT NULL,
  `rider_id` bigint DEFAULT NULL,
  `address_id` bigint DEFAULT NULL,
  `status` varchar(32) NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `item_amount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `delivery_fee` decimal(10,2) NOT NULL DEFAULT '0.00',
  `coupon_id` bigint DEFAULT NULL,
  `coupon_discount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `paid` tinyint(1) NOT NULL DEFAULT '0',
  `payment_time` timestamp NULL DEFAULT NULL,
  `remark` varchar(255) DEFAULT NULL,
  `receiver_name` varchar(64) DEFAULT NULL,
  `receiver_phone` varchar(32) DEFAULT NULL,
  `delivery_address` varchar(255) DEFAULT NULL,
  `user_longitude` decimal(10,6) DEFAULT NULL,
  `user_latitude` decimal(10,6) DEFAULT NULL,
  `estimated_delivery_time` timestamp NULL DEFAULT NULL,
  `cancel_reason` varchar(255) DEFAULT NULL,
  `cancel_time` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `fk_order_user` (`user_id`),
  KEY `fk_order_merchant` (`merchant_id`),
  KEY `fk_order_rider` (`rider_id`),
  CONSTRAINT `fk_order_merchant` FOREIGN KEY (`merchant_id`) REFERENCES `t_merchant` (`id`),
  CONSTRAINT `fk_order_rider` FOREIGN KEY (`rider_id`) REFERENCES `t_rider` (`id`),
  CONSTRAINT `fk_order_user` FOREIGN KEY (`user_id`) REFERENCES `t_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=950023 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

